import React, { useEffect, useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Plus, Settings, Users, BarChart2, X, Search } from 'lucide-react';
import toast from 'react-hot-toast';
import { projectsApi, tasksApi, usersApi } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { getInitials, getStatusLabel, getPriorityClass, formatDate, getErrorMessage } from '../utils/helpers';
import { joinProject, leaveProject, getSocket } from '../services/socket';

const COLUMNS = ['TODO', 'IN_PROGRESS', 'REVIEW', 'DONE'];
const COLUMN_COLORS = {
  TODO: 'var(--text-muted)', IN_PROGRESS: 'var(--accent)',
  REVIEW: 'var(--purple)', DONE: 'var(--green)',
};

function CreateTaskModal({ projectId, onClose, onCreated }) {
  const { user } = useAuth();
  const [form, setForm] = useState({ title: '', description: '', priority: 'MEDIUM', status: 'TODO', dueDate: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.title) return toast.error('Title is required');
    setLoading(true);
    try {
      const { data } = await tasksApi.create(projectId, form);
      onCreated(data.task);
      toast.success('Task created');
    } catch (err) { toast.error(getErrorMessage(err)); }
    finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <span className="modal-title">New Task</span>
          <button className="btn btn-ghost btn-icon" onClick={onClose}><X size={16} /></button>
        </div>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">Title *</label>
            <input className="input" placeholder="Task title" value={form.title}
              onChange={e => setForm(f => ({ ...f, title: e.target.value }))} autoFocus />
          </div>
          <div className="form-group">
            <label className="form-label">Description</label>
            <textarea className="input" rows={3} placeholder="Describe the task..."
              value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
            <div className="form-group">
              <label className="form-label">Status</label>
              <select className="input" value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))}>
                {COLUMNS.map(s => <option key={s} value={s}>{getStatusLabel(s)}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Priority</label>
              <select className="input" value={form.priority} onChange={e => setForm(f => ({ ...f, priority: e.target.value }))}>
                {['LOW','MEDIUM','HIGH'].map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
          </div>
          <div className="form-group">
            <label className="form-label">Due Date</label>
            <input className="input" type="date" value={form.dueDate}
              onChange={e => setForm(f => ({ ...f, dueDate: e.target.value }))} />
          </div>
          <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'flex-end', marginTop: '1rem' }}>
            <button type="button" className="btn btn-secondary" onClick={onClose}>Cancel</button>
            <button type="submit" className="btn btn-primary" disabled={loading}>
              {loading ? <span className="spinner" /> : <><Plus size={15} /> Create Task</>}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

function TaskCard({ task, onClick }) {
  return (
    <div className="kanban-task-card" onClick={() => onClick(task)}>
      <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: 8, marginBottom: 8 }}>
        <span style={{ fontSize: '0.72rem', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)' }}>
          #{task.taskNumber}
        </span>
        <span className={`badge ${getPriorityClass(task.priority)}`}>{task.priority}</span>
      </div>
      <p style={{ fontSize: '0.875rem', fontWeight: 500, lineHeight: 1.4, marginBottom: 10, color: 'var(--text-primary)' }}>
        {task.title}
      </p>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        {task.dueDate && (
          <span style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>{formatDate(task.dueDate)}</span>
        )}
        {task.assignee && (
          <div className="avatar avatar-sm" style={{ marginLeft: 'auto' }}>
            {getInitials(task.assignee.name)}
          </div>
        )}
      </div>
    </div>
  );
}

export default function ProjectDetailPage() {
  const { projectId } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [project, setProject]       = useState(null);
  const [tasks, setTasks]           = useState([]);
  const [loading, setLoading]       = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [search, setSearch]         = useState('');
  const [activeTab, setActiveTab]   = useState('board');

  const loadData = useCallback(async () => {
    try {
      const [pRes, tRes] = await Promise.all([
        projectsApi.get(projectId),
        tasksApi.list(projectId, { limit: 100 }),
      ]);
      setProject(pRes.data.project);
      setTasks(tRes.data.tasks || []);
    } catch { toast.error('Failed to load project'); }
    finally { setLoading(false); }
  }, [projectId]);

  useEffect(() => {
    loadData();
    joinProject(projectId);

    const socket = getSocket();
    if (socket) {
      socket.on('task_created', t => setTasks(prev => [t, ...prev]));
      socket.on('task_updated', t => setTasks(prev => prev.map(x => x._id === t._id ? t : x)));
      socket.on('task_status_changed', ({ taskId, status }) =>
        setTasks(prev => prev.map(x => x._id === taskId ? { ...x, status } : x)));
      socket.on('task_deleted', ({ taskId }) =>
        setTasks(prev => prev.filter(x => x._id !== taskId)));
    }

    return () => {
      leaveProject(projectId);
      if (socket) {
        socket.off('task_created'); socket.off('task_updated');
        socket.off('task_status_changed'); socket.off('task_deleted');
      }
    };
  }, [projectId, loadData]);

  const filteredTasks = tasks.filter(t =>
    !search || t.title.toLowerCase().includes(search.toLowerCase())
  );

  const tasksByStatus = COLUMNS.reduce((acc, s) => {
    acc[s] = filteredTasks.filter(t => t.status === s);
    return acc;
  }, {});

  if (loading) return <div className="empty-state"><div className="spinner spinner-lg" /></div>;
  if (!project) return <div className="empty-state"><p>Project not found</p></div>;

  return (
    <div>
      {/* Header */}
      <div style={{ marginBottom: '1.5rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
          <button className="btn btn-ghost btn-sm" onClick={() => navigate('/projects')} style={{ padding: '2px 6px' }}>
            Projects
          </button>
          <span style={{ color: 'var(--text-muted)' }}>/</span>
          <span style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>{project.name}</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '1rem' }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <span style={{
                fontSize: '0.75rem', fontWeight: 700, fontFamily: 'var(--font-mono)',
                background: 'var(--accent-dim)', color: 'var(--accent)', padding: '2px 8px', borderRadius: 4,
              }}>{project.key}</span>
              <h1 style={{ fontSize: '1.4rem' }}>{project.name}</h1>
            </div>
            {project.description && (
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: 4 }}>
                {project.description}
              </p>
            )}
          </div>
          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <button className="btn btn-secondary btn-sm" onClick={() => navigate(`/analytics/${projectId}`)}>
              <BarChart2 size={14} /> Analytics
            </button>
            <button className="btn btn-primary btn-sm" onClick={() => setShowCreate(true)}>
              <Plus size={14} /> Add Task
            </button>
          </div>
        </div>
      </div>

      {/* Tabs + Search */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.25rem', flexWrap: 'wrap', gap: '0.75rem' }}>
        <div className="tabs">
          {['board','list','members'].map(tab => (
            <button key={tab} className={`tab-btn${activeTab === tab ? ' active' : ''}`}
              onClick={() => setActiveTab(tab)}>
              {tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
        <div className="search-bar">
          <Search size={14} />
          <input placeholder="Search tasks…" value={search} onChange={e => setSearch(e.target.value)} />
        </div>
      </div>

      {/* Board View */}
      {activeTab === 'board' && (
        <div className="kanban-board">
          {COLUMNS.map(col => (
            <div key={col} className="kanban-column">
              <div className="kanban-column-header">
                <h3 style={{ color: COLUMN_COLORS[col] }}>{getStatusLabel(col)}</h3>
                <span style={{
                  fontSize: '0.72rem', fontWeight: 700,
                  background: 'var(--bg-hover)', color: 'var(--text-muted)',
                  padding: '2px 7px', borderRadius: 99,
                }}>{tasksByStatus[col].length}</span>
              </div>
              <div className="kanban-tasks">
                {tasksByStatus[col].map(task => (
                  <TaskCard key={task._id} task={task}
                    onClick={() => navigate(`/projects/${projectId}/tasks/${task._id}`)} />
                ))}
                {tasksByStatus[col].length === 0 && (
                  <div style={{ textAlign: 'center', padding: '1.5rem 0', color: 'var(--text-muted)', fontSize: '0.8rem' }}>
                    No tasks
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* List View */}
      {activeTab === 'list' && (
        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
          <div className="table-wrapper">
            <table className="table">
              <thead>
                <tr>
                  <th>#</th><th>Title</th><th>Status</th><th>Priority</th>
                  <th>Assignee</th><th>Due Date</th>
                </tr>
              </thead>
              <tbody>
                {filteredTasks.map(task => (
                  <tr key={task._id} style={{ cursor: 'pointer' }}
                    onClick={() => navigate(`/projects/${projectId}/tasks/${task._id}`)}>
                    <td style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem', color: 'var(--text-muted)' }}>
                      {project.key}-{task.taskNumber}
                    </td>
                    <td style={{ color: 'var(--text-primary)', fontWeight: 500 }}>{task.title}</td>
                    <td><span className={`badge badge-${task.status.toLowerCase().replace('_','-')}`}>{getStatusLabel(task.status)}</span></td>
                    <td><span className={`badge ${getPriorityClass(task.priority)}`}>{task.priority}</span></td>
                    <td>
                      {task.assignee ? (
                        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                          <div className="avatar avatar-sm">{getInitials(task.assignee.name)}</div>
                          <span style={{ fontSize: '0.82rem' }}>{task.assignee.name}</span>
                        </div>
                      ) : <span style={{ color: 'var(--text-muted)' }}>—</span>}
                    </td>
                    <td style={{ fontSize: '0.82rem' }}>{formatDate(task.dueDate)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredTasks.length === 0 && <div className="empty-state"><p>No tasks found</p></div>}
          </div>
        </div>
      )}

      {/* Members View */}
      {activeTab === 'members' && (
        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
          <table className="table">
            <thead><tr><th>Member</th><th>Email</th><th>Role</th><th>Joined</th></tr></thead>
            <tbody>
              {(project.members || []).map(m => (
                <tr key={m._id}>
                  <td>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <div className="avatar avatar-sm">{getInitials(m.user?.name)}</div>
                      <span style={{ color: 'var(--text-primary)', fontWeight: 500 }}>{m.user?.name}</span>
                    </div>
                  </td>
                  <td>{m.user?.email}</td>
                  <td>
                    <span className={`badge ${m.role === 'ADMIN' ? 'badge-progress' : 'badge-todo'}`}>
                      {m.role}
                    </span>
                  </td>
                  <td>{formatDate(m.joinedAt)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {showCreate && (
        <CreateTaskModal
          projectId={projectId}
          onClose={() => setShowCreate(false)}
          onCreated={(t) => { setTasks(prev => [t, ...prev]); setShowCreate(false); }}
        />
      )}
    </div>
  );
}
